   379→/*
   380→ * Send data to upload to the server, when the socket is writable.
   381→ */
   382→static CURLcode sendrecv_ul(struct Curl_easy *data, int *didwhat)
   383→{
   384→  /* We should not get here when the sending is already done. It
   385→   * probably means that someone set `data-req.keepon |= KEEP_SEND`
   386→   * when it should not. */
   387→  DEBUGASSERT(!Curl_req_done_sending(data));
   388→
   389→  if(!Curl_req_done_sending(data)) {
   390→    *didwhat |= KEEP_SEND;
   391→    return Curl_req_send_more(data);
   392→  }
   393→  return CURLE_OK;
   394→}
   395→
   396→static int select_bits_paused(struct Curl_easy *data, int select_bits)
   397→{
   398→  /* See issue #11982: we really need to be careful not to progress
   399→   * a transfer direction when that direction is paused. Not all parts
   400→   * of our state machine are handling PAUSED transfers correctly. So, we
   401→   * do not want to go there.
   402→   * NOTE: we are only interested in PAUSE, not HOLD. */
   403→
   404→  /* if there is data in a direction not paused, return false */
   405→  if(((select_bits & CURL_CSELECT_IN) &&
   406→      !(data->req.keepon & KEEP_RECV_PAUSE)) ||
   407→     ((select_bits & CURL_CSELECT_OUT) &&
   408→      !(data->req.keepon & KEEP_SEND_PAUSE)))
   409→    return FALSE;
   410→
   411→  return (data->req.keepon & (KEEP_RECV_PAUSE|KEEP_SEND_PAUSE));
   412→}
   413→
   414→/*
   415→ * Curl_sendrecv() is the low-level function to be called when data is to
   416→ * be read and written to/from the connection.
   417→ */
   418→CURLcode Curl_sendrecv(struct Curl_easy *data, struct curltime *nowp)
   419→{
   420→  struct SingleRequest *k = &data->req;
   421→  CURLcode result = CURLE_OK;
   422→  int didwhat = 0;
   423→
   424→  DEBUGASSERT(nowp);
   425→  if(data->state.select_bits) {
   426→    if(select_bits_paused(data, data->state.select_bits)) {
   427→      /* leave the bits unchanged, so they'll tell us what to do when
   428→       * this transfer gets unpaused. */
   429→      result = CURLE_OK;
   430→      goto out;
   431→    }
   432→    data->state.select_bits = 0;
   433→  }
   434→
   435→  /* We go ahead and do a read if we have a readable socket or if the stream
   436→     was rewound (in which case we have data in a buffer) */
   437→  if(k->keepon & KEEP_RECV) {
   438→    result = sendrecv_dl(data, k, &didwhat);
   439→    if(result || data->req.done)
   440→      goto out;
   441→  }
   442→
   443→  /* If we still have writing to do, we check if we have a writable socket. */
   444→  if(Curl_req_want_send(data) || (data->req.keepon & KEEP_SEND_TIMED)) {
   445→    result = sendrecv_ul(data, &didwhat);
   446→    if(result)
   447→      goto out;
   448→  }
   449→
   450→  if(!didwhat) {
   451→    /* Transfer wanted to send/recv, but nothing was possible. */
   452→    result = Curl_conn_ev_data_idle(data);
   453→    if(result)
   454→      goto out;
   455→  }
   456→
   457→  if(Curl_pgrsUpdate(data))
   458→    result = CURLE_ABORTED_BY_CALLBACK;
   459→  else
   460→    result = Curl_speedcheck(data, *nowp);
   461→  if(result)
   462→    goto out;
   463→
   464→  if(k->keepon) {
   465→    if(0 > Curl_timeleft(data, nowp, FALSE)) {
   466→      if(k->size != -1) {
   467→        failf(data, "Operation timed out after %" FMT_TIMEDIFF_T
   468→              " milliseconds with %" FMT_OFF_T " out of %"
   469→              FMT_OFF_T " bytes received",
   470→              Curl_timediff(*nowp, data->progress.t_startsingle),
   471→              k->bytecount, k->size);
   472→      }
   473→      else {
   474→        failf(data, "Operation timed out after %" FMT_TIMEDIFF_T
   475→              " milliseconds with %" FMT_OFF_T " bytes received",
   476→              Curl_timediff(*nowp, data->progress.t_startsingle),
   477→              k->bytecount);
   478→      }
   479→      result = CURLE_OPERATION_TIMEDOUT;
   480→      goto out;
   481→    }
   482→  }
   483→  else {
   484→    /*
   485→     * The transfer has been performed. Just make some general checks before
   486→     * returning.
   487→     */
   488→    if(!(data->req.no_body) && (k->size != -1) &&
   489→       (k->bytecount != k->size) && !k->newurl) {
   490→      failf(data, "transfer closed with %" FMT_OFF_T
   491→            " bytes remaining to read", k->size - k->bytecount);
   492→      result = CURLE_PARTIAL_FILE;
   493→      goto out;
   494→    }
   495→    if(Curl_pgrsUpdate(data)) {
   496→      result = CURLE_ABORTED_BY_CALLBACK;
   497→      goto out;
   498→    }
   499→  }
   500→
   501→  /* If there is nothing more to send/recv, the request is done */
   502→  if(0 == (k->keepon&(KEEP_RECVBITS|KEEP_SENDBITS)))
   503→    data->req.done = TRUE;
   504→
   505→out:
   506→  if(result)
   507→    DEBUGF(infof(data, "Curl_sendrecv() -> %d", result));
   508→  return result;
   509→}
