   173→{
   174→  int sockindex;
   175→
   176→  if(!data || !data->conn)
   177→    return FALSE;
   178→  if(data->conn->sockfd == CURL_SOCKET_BAD)
   179→    return FALSE;
   180→  sockindex = (data->conn->sockfd == data->conn->sock[SECONDARYSOCKET]);
